import { useState } from 'react'
import WarRoom from './pages/WarRoom'
import RMLogin from './components/RMLogin'
import RMDashboard from './components/RMDashboard'
import TeamLeaderLogin from './components/TeamLeaderLogin'
import TeamLeaderDashboard from './components/TeamLeaderDashboard'

function App() {
  const [userType, setUserType] = useState('warroom')
  const [isLoggedIn, setIsLoggedIn] = useState(false)
  const [currentRMId, setCurrentRMId] = useState(null)
  const [currentTLId, setCurrentTLId] = useState(null)

  const handleRMLogin = (rmId) => {
    setCurrentRMId(rmId)
    setIsLoggedIn(true)
    setUserType('rm')
  }

  const handleTLLogin = (tlId) => {
    setCurrentTLId(tlId)
    setIsLoggedIn(true)
    setUserType('tl')
  }

  const handleLogout = () => {
    setIsLoggedIn(false)
    setCurrentRMId(null)
    setCurrentTLId(null)
    setUserType('warroom')
  }

  // Admin War Room View
  if (userType === 'warroom') {
    return (
      <div>
        <div style={{
          position: 'fixed',
          top: '10px',
          right: '20px',
          zIndex: 1000,
          display: 'flex',
          gap: '10px'
        }}>
          <button
            onClick={() => setUserType('rm')}
            style={{
              padding: '8px 16px',
              background: '#28a745',
              color: 'white',
              border: 'none',
              borderRadius: '4px',
              cursor: 'pointer'
            }}
          >
            👤 RM Portal
          </button>
          <button
            onClick={() => setUserType('tl')}
            style={{
              padding: '8px 16px',
              background: '#ff9800',
              color: 'white',
              border: 'none',
              borderRadius: '4px',
              cursor: 'pointer'
            }}
          >
            👥 Team Leader Portal
          </button>
        </div>
        <WarRoom />
      </div>
    )
  }

  // RM Portal View
  if (userType === 'rm') {
    if (!isLoggedIn) {
      return <RMLogin onLogin={handleRMLogin} />
    }
    return (
      <div>
        <div style={{
          position: 'fixed',
          top: '10px',
          right: '20px',
          zIndex: 1000,
          display: 'flex',
          gap: '10px'
        }}>
          <button
            onClick={() => setUserType('warroom')}
            style={{
              padding: '8px 16px',
              background: '#6c757d',
              color: 'white',
              border: 'none',
              borderRadius: '4px',
              cursor: 'pointer'
            }}
          >
            🔐 Admin War Room
          </button>
          <button
            onClick={() => setUserType('tl')}
            style={{
              padding: '8px 16px',
              background: '#ff9800',
              color: 'white',
              border: 'none',
              borderRadius: '4px',
              cursor: 'pointer'
            }}
          >
            👥 Team Leader
          </button>
        </div>
        <RMDashboard rmId={currentRMId} onLogout={handleLogout} />
      </div>
    )
  }

  // Team Leader Portal View
  if (userType === 'tl') {
    if (!isLoggedIn) {
      return <TeamLeaderLogin onLogin={handleTLLogin} />
    }
    return (
      <div>
        <div style={{
          position: 'fixed',
          top: '10px',
          right: '20px',
          zIndex: 1000,
          display: 'flex',
          gap: '10px'
        }}>
          <button
            onClick={() => setUserType('warroom')}
            style={{
              padding: '8px 16px',
              background: '#6c757d',
              color: 'white',
              border: 'none',
              borderRadius: '4px',
              cursor: 'pointer'
            }}
          >
            🔐 Admin War Room
          </button>
          <button
            onClick={() => setUserType('rm')}
            style={{
              padding: '8px 16px',
              background: '#28a745',
              color: 'white',
              border: 'none',
              borderRadius: '4px',
              cursor: 'pointer'
            }}
          >
            👤 RM Portal
          </button>
        </div>
        <TeamLeaderDashboard tlId={currentTLId} onLogout={handleLogout} />
      </div>
    )
  }
}

export default App